(function(){
  var $=function(id){return document.getElementById(id);};
  var fmt=function(n){return '$'+Math.round(n).toLocaleString('en-US');};
  function calc(){
    var price=+$('dpPrice').value, pct=+$('dpPct').value;
    var down=price*pct/100, base=price-down, ufmip=base*0.0175;
    $('dpvPrice').textContent=fmt(price);
    $('dpvPct').textContent=pct+'% · '+fmt(down);
    $('dpDown').innerHTML=fmt(down);
    $('dpPctOut').textContent=pct+'%';
    $('dpLoanBase').textContent=fmt(base);
    $('dpMin35').textContent=fmt(price*0.035);
    $('dpMin10').textContent=fmt(price*0.10);
    $('dpLoanTotal').textContent=fmt(base+ufmip);
  }
  ['dpPrice','dpPct'].forEach(function(id){$(id).addEventListener('input',calc);});
  calc();
})();
